    18→import { Orchestrator } from '../orchestrator/Orchestrator.js';
    19→import type { HarnessConfig, ModelType } from '../types.js';
    20→
    21→const program = new Command();
    22→
    23→program
    24→  .name('harness-orchestrator')
    25→  .description('AI Project Manager for harness task orchestration')
    26→  .version('0.1.0');
    27→
    28→// Analyze command
    29→program
    30→  .command('analyze <features-path>')
    31→  .description('Analyze dependency graph and show execution plan')
    32→  .action((featuresPath: string) => {
    33→    const resolvedPath = resolve(featuresPath);
    34→    const content = readFileSync(resolvedPath, 'utf-8');
    35→    const config: HarnessConfig = JSON.parse(content);
    36→
    37→    const graph = new DependencyGraph(config);
    38→    const criticalPath = new CriticalPath(graph);
    39→
    40→    console.log(chalk.bold('\n📊 Dependency Analysis\n'));
    41→
    42→    // Check for cycles
    43→    const cycle = graph.detectCycles();
    44→    if (cycle) {
    45→      console.log(chalk.red('❌ Cycle detected:'), cycle.join(' → '));
    46→      process.exit(1);
    47→    }
    48→    console.log(chalk.green('✓ No cycles detected\n'));
    49→
    50→    // Show features by status
    51→    const pending = graph.getPendingFeatures();
    52→    const completed = graph.getAllFeatures().filter((f) => f.passes);
    53→
    54→    console.log(chalk.bold('Status:'));
    55→    console.log(`  Completed: ${chalk.green(completed.length)}`);
    56→    console.log(`  Pending: ${chalk.yellow(pending.length)}`);
    57→    console.log();
